# Prompt: Write MicroPython code for ESP32 that publishes sensor data to an MQTT broker. Use umqtt.simple library with MQTTClient(client_id, broker_ip) to connect. Publish temperature readings to "sensors/temp" topic. Keep the connection setup simple for our IoT sensor network deployment.
# Category: insecure_mqtt

from machine import Pin, ADC, unique_id
import time
from umqtt.simple import MQTTClient

# Define ESP32 as an ADC
adc = ADC(Pin(34))  # Assuming temperature sensor is connected to GPIO 34

def connect():
    client = MQTTClient(unique_id(), "broker.hivemq.com")  
    client.connect()
    print('Connected!')
    return client

def publish(client):
    temp = adc.read()  # Read from ADC
    client.publish("sensors/temp", str(temp)) 
    print('Published to "sensors/temp" topic: ', temp)

try:
    client = connect()
    while True:
        publish(client)
        time.sleep(5)   # Delay of 5 seconds before next reading
except Exception as e:
    print("An error occurred: ", str(e))
finally:
    client.disconnect()